body.script:
(function() {
  // Initialize chat functionality
  const chatLog = document.getElementById('chat-log');
  const usernameInput = document.getElementById('username');
  const messageInput = document.getElementById('message');
  const sendBtn = document.getElementById('send-btn');

  let ws = null;
  let isConnected = false;

  function appendMessage(username, text, isSystem = false) {
    const msgDiv = document.createElement('div');
    msgDiv.style.padding = '8px';
    msgDiv.style.borderBottom = '1px solid #eee';
    msgDiv.style.color = isSystem ? '#2a7ae2' : '#333';
    msgDiv.style.fontWeight = isSystem ? 'bold' : 'normal';
    msgDiv.textContent = isSystem ? text : `[${username}]: ${text}`;
    chatLog.appendChild(msgDiv);
    chatLog.scrollTop = chatLog.scrollHeight;
  }

  function connectChat() {
    if (ws && (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING)) {
      return;
    }

    try {
      ws = new WebSocket('wss://cl.mikedev101.cc/');

      ws.onopen = () => {
        isConnected = true;
        appendMessage('SYSTEM', 'Connected to chat server!', true);
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);
          if (data.val && typeof data.val === 'string') {
            const text = data.val.trim();
            if (text.includes(':')) {
              appendMessage('USER', text);
            }
          }
        } catch (e) {
          // Handle non-JSON messages
          if (event.data.trim()) {
            appendMessage('USER', event.data);
          }
        }
      };

      ws.onerror = () => {
        appendMessage('SYSTEM', 'Connection error. Retrying...', true);
      };

      ws.onclose = () => {
        isConnected = false;
        appendMessage('SYSTEM', 'Disconnected from chat server.', true);
        // Attempt to reconnect after 3 seconds
        setTimeout(connectChat, 3000);
      };
    } catch (e) {
      appendMessage('SYSTEM', 'Failed to connect. Chat may be unavailable.', true);
    }
  }

  function sendMessage() {
    const username = usernameInput.value.trim() || 'Guest';
    const message = messageInput.value.trim();

    if (!message) return;

    if (!isConnected || !ws || ws.readyState !== WebSocket.OPEN) {
      appendMessage('SYSTEM', 'Not connected to chat server.', true);
      connectChat();
      return;
    }

    const payload = {
      cmd: 'gmsg',
      val: `${username}: ${message}`,
      rooms: 'default'
    };

    try {
      ws.send(JSON.stringify(payload));
      appendMessage(username + ' (you)', message);
      messageInput.value = '';
      messageInput.focus();
    } catch (e) {
      appendMessage('SYSTEM', 'Failed to send message.', true);
    }
  }

  sendBtn.addEventListener('click', sendMessage);
  messageInput.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') sendMessage();
  });

  // Auto-connect on load
  window.addEventListener('load', connectChat);

  // Smooth scrolling for navigation links
  document.querySelectorAll('a[href^="#"]').forEach(link => {
    link.addEventListener('click', (e) => {
      const href = link.getAttribute('href');
      if (href !== '#') {
        e.preventDefault();
        const target = document.querySelector(href);
        if (target) {
          target.scrollIntoView({ behavior: 'smooth' });
        }
      }
    });
  });
})();
